import{_ as e,o as l,c as n,a2 as a}from"./chunks/framework.BQ1gajhD.js";const d="/beijing-travel-guide/qing-beijing-map.svg",c=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"北京旅游攻略","text":"探索千年帝都","tagline":"从紫禁城到长城，从皇家园林到现代都市——一站式北京旅行指南","actions":[{"theme":"brand","text":"开始探索","link":"/landmarks/forbidden-city"},{"theme":"alt","text":"查看景点","link":"/landmarks/"}],"image":{"src":"/hero-image.svg","alt":"北京"}},"features":[{"icon":"🏛️","title":"名胜古迹","details":"故宫、天坛、长城、颐和园等皇家建筑，感受千年帝都的恢弘气势","link":"/landmarks/forbidden-city"},{"icon":"📜","title":"近代历史","details":"从圆明园到北大红楼，探寻中国近现代历史的沧桑巨变","link":"/history/yuanmingyuan-ruins"},{"icon":"⛪","title":"宗教建筑","details":"天主教堂、佛教寺院、道教宫观，多元宗教文化在北京的交融","link":"/religion/catholic-churches"},{"icon":"🏛️","title":"博物馆","details":"国博、首博、科技馆等，深入了解中华文明的璀璨瑰宝","link":"/museums/national-museum"},{"icon":"🌳","title":"城市公园","details":"皇家园林与现代公园，体验北京独特的城市绿色空间","link":"/parks/beihai-park"},{"icon":"🗺️","title":"实用攻略","details":"交通指南、最佳游览路线、门票预约等实用信息一应俱全","link":"/guide/"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),i={name:"index.md"};function r(s,t,o,g,x,h){return l(),n("div",null,[...t[0]||(t[0]=[a('<h2 id="🎯-热门推荐" tabindex="-1">🎯 热门推荐 <a class="header-anchor" href="#🎯-热门推荐" aria-label="Permalink to &quot;🎯 热门推荐&quot;">​</a></h2><div class="highlights"><h3 id="🏆-必游-top-5" tabindex="-1">🏆 必游 TOP 5 <a class="header-anchor" href="#🏆-必游-top-5" aria-label="Permalink to &quot;🏆 必游 TOP 5&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">排名</th><th style="text-align:left;">景点</th><th style="text-align:left;">特色</th><th style="text-align:center;">建议时长</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;"><strong>故宫博物院</strong></td><td style="text-align:left;">世界最大宫殿建筑群，明清两代皇宫</td><td style="text-align:center;">半天-1天</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;"><strong>八达岭长城</strong></td><td style="text-align:left;">万里长城精华段，&quot;不到长城非好汉&quot;</td><td style="text-align:center;">半天</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;"><strong>颐和园</strong></td><td style="text-align:left;">中国古典园林巅峰之作，皇家园林博物馆</td><td style="text-align:center;">半天</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;"><strong>天坛</strong></td><td style="text-align:left;">明清皇帝祭天祈谷之所，建筑艺术杰作</td><td style="text-align:center;">3-4小时</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:left;"><strong>北海公园</strong></td><td style="text-align:left;">现存最古老皇家园林，白塔琼岛</td><td style="text-align:center;">2-3小时</td></tr></tbody></table></div><h2 id="🏛️-清代北京城布局" tabindex="-1">🏛️ 清代北京城布局 <a class="header-anchor" href="#🏛️-清代北京城布局" aria-label="Permalink to &quot;🏛️ 清代北京城布局&quot;">​</a></h2><p>清代北京城采用&quot;四重城郭&quot;格局，从中心向外依次为：<strong>紫禁城</strong>、<strong>皇城</strong>、<strong>内城</strong>、<strong>外城</strong>。</p><p><img src="'+d+'" alt="清代北京城平面图"></p><div class="map-description"><h3 id="四重城郭结构" tabindex="-1">四重城郭结构 <a class="header-anchor" href="#四重城郭结构" aria-label="Permalink to &quot;四重城郭结构&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">层级</th><th style="text-align:left;">范围</th><th style="text-align:left;">功能</th><th style="text-align:left;">主要建筑</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>紫禁城</strong></td><td style="text-align:left;">核心区</td><td style="text-align:left;">皇帝办公起居</td><td style="text-align:left;">太和殿、乾清宫、御花园</td></tr><tr><td style="text-align:center;"><strong>皇城</strong></td><td style="text-align:left;">环绕紫禁城</td><td style="text-align:left;">皇家服务机构</td><td style="text-align:left;">太庙、社稷坛、景山、西苑</td></tr><tr><td style="text-align:center;"><strong>内城</strong></td><td style="text-align:left;">北城区</td><td style="text-align:left;">八旗驻防</td><td style="text-align:left;">钟鼓楼、胡同民居</td></tr><tr><td style="text-align:center;"><strong>外城</strong></td><td style="text-align:left;">南城区</td><td style="text-align:left;">平民居住区</td><td style="text-align:left;">天坛、先农坛</td></tr></tbody></table><h3 id="中轴线" tabindex="-1">中轴线 <a class="header-anchor" href="#中轴线" aria-label="Permalink to &quot;中轴线&quot;">​</a></h3><p>北京中轴线南起永定门，北至钟鼓楼，全长7.8公里。沿线分布着：</p><p><strong>永定门</strong> → <strong>正阳门</strong> → <strong>天安门</strong> → <strong>紫禁城</strong> → <strong>景山</strong> → <strong>钟鼓楼</strong></p><blockquote><p>💡 <strong>提示</strong>：点击上方平面图可放大查看详细布局。</p></blockquote></div><h2 id="📅-最佳游览季节" tabindex="-1">📅 最佳游览季节 <a class="header-anchor" href="#📅-最佳游览季节" aria-label="Permalink to &quot;📅 最佳游览季节&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">季节</th><th style="text-align:left;">时间</th><th style="text-align:left;">推荐景点</th><th style="text-align:left;">注意事项</th></tr></thead><tbody><tr><td style="text-align:center;">🌸 春季</td><td style="text-align:left;">3-5月</td><td style="text-align:left;">玉渊潭樱花、植物园桃花</td><td style="text-align:left;">早晚温差大，注意保暖</td></tr><tr><td style="text-align:center;">☀️ 夏季</td><td style="text-align:left;">6-8月</td><td style="text-align:left;">颐和园荷花、北海划船</td><td style="text-align:left;">防暑防晒，避开正午</td></tr><tr><td style="text-align:center;">🍂 秋季</td><td style="text-align:left;">9-11月</td><td style="text-align:left;">香山红叶、故宫银杏</td><td style="text-align:left;">最佳旅游季，人流量大</td></tr><tr><td style="text-align:center;">❄️ 冬季</td><td style="text-align:left;">12-2月</td><td style="text-align:left;">故宫雪景、什刹海滑冰</td><td style="text-align:left;">注意保暖，部分景点提前闭馆</td></tr></tbody></table><h2 id="🚇-交通贴士" tabindex="-1">🚇 交通贴士 <a class="header-anchor" href="#🚇-交通贴士" aria-label="Permalink to &quot;🚇 交通贴士&quot;">​</a></h2><ul><li><strong>地铁</strong>：覆盖主要景点，推荐使用「亿通行」APP</li><li><strong>公交</strong>：1元起价，可刷码乘车</li><li><strong>出租车/网约车</strong>：起步价14元，高峰期较拥堵</li><li><strong>共享单车</strong>：适合短距离接驳，注意禁停区域</li></ul>',10)])])}const f=e(i,[["render",r]]);export{c as __pageData,f as default};
